async function simulateHighTraffic(couponService, couponCode, numUsers) {
    console.log(`\nSimulating ${numUsers} users trying to redeem '${couponCode}'...`);
    const promises = [];
    for (let i = 0; i < numUsers; i++) {
        promises.push(couponService.redeemCoupon(couponCode, `user_${i + 1}`));
    }

    const results = await Promise.all(promises);

    let successCount = 0;
    let failedReasons = {};

    results.forEach(result => {
        if (result.success) {
            successCount++;
        } else {
            failedReasons[result.reason] = (failedReasons[result.reason] || 0) + 1;
        }
    });

    console.log(`\n--- Redemption Results for '${couponCode}' ---`);
    console.log(`Total attempts: ${numUsers}`);
    console.log(`Successful redemptions: ${successCount}`);
    console.log("Failed reasons:", failedReasons);
    console.log("Final coupon status:", couponService.getCouponStatus(couponCode));
}

